  "sections": {
    "background": {
      "sectionStatus": "done",
      "items": {
        "trigger": "R-SWUI-002 已完成架构研究与落地前决策收口；仓库具备 agent 文档、ui-consumer 接入证明与私有 registry 发布能力，但缺少统一人类门户、安装前 Agent 查询面（swui MCP）与 registry 聚合页。",
        "affectedParties": "@swui/ui、@swui/ui-tokens 维护者；skywalker 及所有消费应用开发者；使用 Cursor/Agent 的组织内工程师。",
        "whyNow": "R-SWUI-001 主题/尺寸治理已 delivered（F-SWQT-0001–0003）；暴露面与分发面成为下一瓶颈。registry metadata 匿名可读、Host 双 MCP 槽位（暂不开 sws facade）已用户确认。",
        "bullets": [
          "交付 R-SWUI-002 §11.1 MVP：examples/portal + ui.swqt.net/mcp + registry 方案 A。",
          "目标态必须符合设计系统行业最佳实践：文档公开、包分发 registry 权威、SSOT 单向同步、职责分离（portal ≠ 产品壳 ≠ 测试夹具）。",
          "Phase 2 全量 catalog demo 与扩展 MCP tools 不在本 Feature；Playwright 矩阵继续留 ui-consumer（R-SWUI-004）。"
        ]
      }
    },
    "problem-statement": {
      "sectionStatus": "done",
      "items": {
        "coreProblem": "设计系统知识、安装路径与版本信息分散于 repo Markdown、node_modules 与 npm.inet.swqt.net；人类无法按 COMPONENT-CATALOG 统一浏览，Agent 安装前无法结构化查询 adoption/版本/peer，且无 ui.swqt.net 类 canonical 入口。",
        "nonGoals": [
          "不在 @swui/ui 或 @swui/ui-tokens 包内嵌 MCP server、registry 或产品 AppShell/TopBar/业务路由。",
          "门户不自托管 tarball、不提供 tarball 下载 UI；不绕过 registry install 鉴权。",
          "不扩展 examples/ui-consumer 为全量 catalog 文档站；不将 Playwright 截图基线迁入 portal。",
          "不同步启动 sws 本地 facade 联邦（路径 B）；不在中心 SWS MCP 代理 swui。",
          "MVP 不含 Storybook MCP 试点、全量组件 demo 页、swui.catalog.search / swui.component.get（属 Phase 2）。",
          "不强制 skywalker showcase 立即下线（渐进 deprecate，Phase 2 后评估）。"
        ]
      }
    },
    "context-constraints": {
      "sectionStatus": "done",
      "items": {
        "researchSource": "docs/research/R-SWUI-002-design-system-portal-mcp-registry-research.md §13 落地前决策（已确认）",
        "projectConstraints": [
          "共享 Web UI 设计系统仓库；portal 在 examples/portal，遵守 packages/ui/AGENTS.md 层边界。",
          "npm 分发方案 A：npm.inet.swqt.net 为唯一 tarball 源；publish 仍走 scripts/publish.sh。",
          "Agent 纪律：未安装包用 portal MCP；已安装包以 node_modules/@swui/ui/AGENTS.md 为版本锁定真源。"
        ],
        "technicalConstraints": [
          "静态门户：Vite + React（与 ui-consumer 技术栈一致）。",
          "MCP：同域 https://ui.swqt.net/mcp HTTP handler（Node）；命名空间 swui://。",
          "文档 SSOT：packages/ui/docs/*、AGENTS.md、llms.txt → sync-docs.mjs → portal .generated/；禁止手改副本。",
          "registry：匿名读 metadata；15min TTL stale 缓存；install 需 _authToken。"
        ],
        "axisPositioning": "required: application=design-system-portal; surface=human-site+MCP+registry-ui; technology=Vite+React+Node-MCP+Bun; validation=build+sync-check+MCP-smoke; externalDependency=ui.swqt.net-deploy+ingress.",
        "axisSplitSignals": "SSOT 同步管道、registry 只读集成、MCP HTTP 服务、CI/deploy 验收有独立失败面；单 Feature 因共同关闭 R-SWUI-002 MVP 目标态。",
        "axisSnapshot": "四 Step 顺序依赖：portal 骨架 → registry 页 → MCP 服务 → CI/deploy 与文档 handoff。",
        "targetStateArchitecture": {
          "canonicalEntry": "https://ui.swqt.net",
          "routes": {
            "/": "Overview — 库定位、skywalker 关系、安装入口",
            "/conventions/*": "DESIGN-SUMMARY、DO-AND-DONT、ADOPTION（sync-docs 生成）",
            "/packages": "@swui/ui + @swui/ui-tokens 版本、peer、install、.npmrc",
            "/mcp": "swui HTTP MCP — resources + swui.package.get/installHint",
            "/agent": "MCP 连接说明、与 AGENTS.md / sw mcp 分工"
          },
          "hostMcp": {
            "sw": "现有 methodology / workflow（不变）",
            "swui": "url https://ui.swqt.net/mcp（新增第二槽位）"
          },
          "ssotFlow": "packages/*/docs → sync-docs.mjs → portal .generated/ + MCP resource index → deploy；npm tarball 仅经 registry",
          "layerBoundary": {
            "@swui/ui": "运行时库 + 随包 agent 文档",
            "examples/portal": "展示 + MCP + registry UI",
            "examples/ui-consumer": "adoption 证明 + Playwright 矩阵",
            "npm.inet.swqt.net": "publish / install / semver / tarball"
          }
        }
      }
    },
